from dataclasses import dataclass, field
from datetime import datetime, timedelta
from enum import Enum
from typing import Optional

class StoryStatus(Enum):
    BACKLOG = "backlog"
    TODO = "to do"
    IN_PROGRESS = "in progress"
    REVIEW = "review"
    DONE = "done"

@dataclass
class UserStory:
    id: int
    title: str
    description: str
    points: int  # Story points (1, 2, 3, 5, 8, 13)
    status: StoryStatus = StoryStatus.BACKLOG
    assignee: Optional[str] = None

@dataclass
class Sprint:
    number: int
    start_date: datetime
    end_date: datetime
    stories: list = field(default_factory=list)
    capacity: int = 40  # Total story points per sprint

    @property
    def committed_points(self) -> int:
        return sum(s.points for s in self.stories)

    @property
    def remaining_capacity(self) -> int:
        return self.capacity - self.committed_points

    def add_story(self, story: UserStory) -> bool:
        if self.committed_points + story.points <= self.capacity:
            story.status = StoryStatus.TODO
            self.stories.append(story)
            return True
        return False

    def velocity(self) -> dict:
        done = [s for s in self.stories if s.status == StoryStatus.DONE]
        return {
            "committed": self.committed_points,
            "completed": sum(s.points for s in done),
            "stories_done": len(done),
            "stories_total": len(self.stories)
        }

class ScrumBoard:
    def __init__(self, team_name: str):
        self.team_name = team_name
        self.sprints: list[Sprint] = []
        self.product_backlog: list[UserStory] = []
        self.current_sprint: Optional[Sprint] = None

    def add_to_backlog(self, story: UserStory):
        story.status = StoryStatus.BACKLOG
        self.product_backlog.append(story)
        self.product_backlog.sort(key=lambda s: s.points)

    def start_sprint(self, sprint: Sprint):
        self.current_sprint = sprint
        self.sprints.append(sprint)

    def daily_standup(self) -> str:
        if not self.current_sprint:
            return "No active sprint"
        report = f"Sprint {self.current_sprint.number} Standup:\n"
        for story in self.current_sprint.stories:
            report += f"  [{story.status.value:12s}] {story.title} ({story.assignee or 'unassigned'})\n"
        return report

    def sprint_review(self) -> dict:
        if not self.current_sprint:
            return {}
        return self.current_sprint.velocity()

# Usage
board = ScrumBoard("CampusSync Dev")

# Add stories to backlog
board.add_to_backlog(UserStory(1, "User login", "As a user, I want to log in", 5))
board.add_to_backlog(UserStory(2, "Dashboard", "As a user, I want to see my dashboard", 8))
board.add_to_backlog(UserStory(3, "Notifications", "As a user, I want notifications", 3))
board.add_to_backlog(UserStory(4, "Search", "As a user, I want to search", 5))
board.add_to_backlog(UserStory(5, "Profile edit", "As a user, I want to edit my profile", 3))

# Start sprint
sprint1 = Sprint(1, datetime.now(), datetime.now() + timedelta(days=14))
board.start_sprint(sprint1)

# Commit stories
for story in board.product_backlog[:3]:
    sprint1.add_story(story)

# Move story to done
sprint1.stories[0].status = StoryStatus.DONE
sprint1.stories[0].assignee = "Alice"

print(board.daily_standup())
print(f"Sprint Review: {board.sprint_review()}")
```

