from dataclasses import dataclass, field
from datetime import datetime
from typing import Optional
import json

@dataclass
class KanbanCard:
    id: int
    title: str
    description: str
    priority: str  # low, medium, high, critical
    created_at: datetime = field(default_factory=datetime.now)
    assignee: Optional[str] = None
    tags: list = field(default_factory=list)

@dataclass
class KanbanColumn:
    name: str
    wip_limit: int  # Maximum cards in this column
    cards: list = field(default_factory=list)

    @property
    def is_at_limit(self) -> bool:
        return len(self.cards) >= self.wip_limit

    def add_card(self, card: KanbanCard) -> bool:
        if self.is_at_limit:
            return False
        self.cards.append(card)
        return True

    def remove_card(self, card_id: int) -> Optional[KanbanCard]:
        for i, card in enumerate(self.cards):
            if card.id == card_id:
                return self.cards.pop(i)
        return None

class KanbanBoard:
    def __init__(self, name: str):
        self.name = name
        self.columns: list[KanbanColumn] = []

    def add_column(self, name: str, wip_limit: int):
        self.columns.append(KanbanColumn(name, wip_limit))

    def move_card(self, card_id: int, from_col: int, to_col: int) -> bool:
        source = self.columns[from_col]
        target = self.columns[to_col]
        card = source.remove_card(card_id)
        if not card:
            return False
        if not target.add_card(card):
            source.add_card(card)  # Put it back
            return False
        return True

    def display(self) -> str:
        output = f"=== {self.name} ===\n"
        max_cards = max(len(col.cards) for col in self.columns)
        for col in self.columns:
            wip_status = f"({len(col.cards)}/{col.wip_limit})"
            output += f"\n{col.name} {wip_status}:\n"
            for card in col.cards:
                priority_marker = {"critical": "!!!", "high": "!!", "medium": "!", "low": ""}
                output += f"  [{priority_marker[card.priority]}] {card.title}"
                if card.assignee:
                    output += f" ({card.assignee})"
                output += "\n"
        return output

    def metrics(self) -> dict:
        total_cards = sum(len(col.cards) for col in self.columns)
        done_col = self.columns[-1] if self.columns else None
        return {
            "total_cards": total_cards,
            "done": len(done_col.cards) if done_col else 0,
            "throughput": len(done_col.cards) if done_col else 0,
            "columns": {col.name: len(col.cards) for col in self.columns}
        }

# Create board
board = KanbanBoard("CampusSync Kanban")
board.add_column("Backlog", wip_limit=20)
board.add_column("To Do", wip_limit=5)
board.add_column("In Progress", wip_limit=3)
board.add_column("Review", wip_limit=2)
board.add_column("Done", wip_limit=999)

# Add cards
cards = [
    KanbanCard(1, "Fix login bug", "Users can't log in with SSO", "critical", assignee="Alice", tags=["bug"]),
    KanbanCard(2, "Add dark mode", "Implement dark theme", "medium", assignee="Bob", tags=["feature"]),
    KanbanCard(3, "API rate limiting", "Add rate limits to public API", "high", tags=["backend"]),
    KanbanCard(4, "Update docs", "API documentation update", "low", tags=["docs"]),
    KanbanCard(5, "Database migration", "Migrate to PostgreSQL 16", "high", assignee="Charlie", tags=["infra"]),
]
for card in cards:
    board.columns[0].add_card(card)

# Move cards through workflow
board.move_card(1, 0, 1)  # Backlog -> To Do
board.move_card(1, 1, 2)  # To Do -> In Progress
board.move_card(2, 0, 1)  # Backlog -> To Do
board.move_card(1, 2, 3)  # In Progress -> Review

print(board.display())
print(f"Metrics: {json.dumps(board.metrics(), indent=2)}")
